SELECT SUM(population) AS total_population
FROM area_codes
WHERE region = 'United Kingdom';

SELECT area_name
FROM area_codes
WHERE area_code = '0';

SELECT area_name, population
FROM area_codes
WHERE region = 'United Kingdom';

SELECT MAX(intervention_date) AS latest_intervention
FROM interventions
WHERE area_code = '0';

SELECT area_code, area_name
FROM area_codes
ORDER BY area_name ASC;
